// =========================================================
// SISENDI NORMALIZER — kõik 3 triggerit ühele kujule
// =========================================================
const input = $input.first().json;
const now = new Date().toISOString();
const staticData = $getWorkflowStaticData('global');
staticData.lastDraftByChat = staticData.lastDraftByChat || {};
staticData.cycleIndex = staticData.cycleIndex || 0;

let source, brief, channel, segment_hint, tone, category, message, product_hint, feedback, chat_id, user_name;

// 1) FORM TRIGGER
if (input['Kampaania nimi']) {
  source = 'form';
  brief = input['Kampaania nimi'];
  channel = input['Kanal'] || 'Instagram';
  category = input['Tootekategooria'] || 'naiste riided';
  segment_hint = input['Sihtrühm'] || 'SEG-01';
  tone = input['Toon'] || 'inspireeriv';
  message = input['Põhisõnum'] || '';
  product_hint = input['Konkreetne toode (vabatahtlik)'] || '';
  feedback = '';
  chat_id = 'CHAT_ID_HERE'; // Asenda oma Telegram chat ID-ga
  user_name = 'turundaja (vorm)';
}
// 2) TELEGRAM TRIGGER
else if (input.message?.text) {
  source = 'telegram';
  const text = input.message.text.trim();
  chat_id = input.message.chat.id;
  user_name = input.message.from?.first_name || 'kasutaja';

  if (/^paranda:/i.test(text)) {
    feedback = text.replace(/^paranda:\s*/i, '').trim();
    brief = 'revision';
    channel = 'Telegram';
    const last = staticData.lastDraftByChat[String(chat_id)];
    message = last?.draft_text || '';
    product_hint = last?.product_hint || '';
    segment_hint = last?.segment_hint || 'SEG-01';
    category = last?.category || 'naiste riided';
    tone = 'sama nagu eelmine';
  } else if (/^\/reklaam/i.test(text)) {
    product_hint = text.replace(/^\/reklaam\s*/i, '').trim();
    brief = 'kiire reklaam';
    channel = 'Telegram';
    message = 'kiire reklaam Telegrami kanalile';
    segment_hint = 'SEG-06'; // Teadlikud noored
    category = '';
    tone = 'inspireeriv';
    feedback = '';
  } else {
    brief = text.split('\n')[0] || 'vaba brief';
    channel = 'Kõik kanalid';
    message = text;
    segment_hint = 'SEG-01';
    category = '';
    tone = 'inspireeriv';
    product_hint = '';
    feedback = '';
  }
}
// 3) SCHEDULE TRIGGER (tsükliline)
else {
  source = 'schedule';
  const products = ['US-P-101','US-P-102','US-P-103','US-P-201','US-P-202','US-P-203','US-P-301','US-P-302','US-P-303','US-P-401','US-P-402','US-P-403'];
  const idx = staticData.cycleIndex % products.length;
  product_hint = products[idx];
  staticData.cycleIndex = idx + 1;
  brief = 'Päevane auto-draft';
  channel = 'Kõik kanalid';
  message = 'Hooaja sisuline postitus';
  segment_hint = 'SEG-06';
  category = '';
  tone = 'inspireeriv';
  feedback = '';
  chat_id = 'CHAT_ID_HERE';
  user_name = 'auto-schedule';
}

return [{
  json: {
    source, brief, channel, category, segment_hint, tone, message, product_hint, feedback,
    chat_id: String(chat_id), user_name, created_at: now,
    draft_id: 'N4-' + now.replace(/[-:.TZ]/g,'').slice(0,14) + '-' + Math.random().toString(36).slice(2,5).toUpperCase()
  }
}];

// =========================================================
// N4 ANDMEPAKK + LOOKUP — Ha-tase 100%
// =========================================================
