const PRODUCTS = [
  {product_id:'US-P-101',product_name:'Linen Flow kleit',category:'naiste riided',price_eur:89,eco_certified:true,key_message:'hingav linasest segust kleit',content_angle:'ajatu kevadine garderoob'},
