  {product_id:'US-P-402',product_name:'Relaxed linen shirt',category:'meeste riided',price_eur:74,eco_certified:true,key_message:'linasegune suvesärk',content_angle:'hingav ja rahulik stiil'},
  {product_id:'US-P-403',product_name:'Travel pouch',category:'aksessuaarid',price_eur:24,eco_certified:true,key_message:'väike tarvikute kott',content_angle:'korrahoid liikumisel'}
];

const SEGMENTS = [
  {segment_id:'SEG-01',segment_name:'Tallinn gold kliendid',city:'Tallinn',loyalty_tier:'gold',main_need:'kvaliteetsed ja ajatud esemed',preferred_channel:'Instagram',tone_hint:'premium ja inspireeriv'},
  {segment_id:'SEG-02',segment_name:'Tartu silver kliendid',city:'Tartu',loyalty_tier:'silver',main_need:'praktiline argimood',preferred_channel:'Email',tone_hint:'selge ja kasulik'},
  {segment_id:'SEG-03',segment_name:'Pärnu suveostjad',city:'Pärnu',loyalty_tier:'bronze',main_need:'kerged kevad- ja suveriided',preferred_channel:'Instagram',tone_hint:'soe ja hooajaline'},
  {segment_id:'SEG-04',segment_name:'Narva uued kliendid',city:'Narva',loyalty_tier:'new',main_need:'usaldus ja poe tutvustus',preferred_channel:'Facebook',tone_hint:'lihtne ja kutsuv'},
  {segment_id:'SEG-05',segment_name:'E-poe korduvostjad',city:'online',loyalty_tier:'gold',main_need:'kiire valik ja sobivus',preferred_channel:'Email',tone_hint:'personaalne ja konkreetne'},
  {segment_id:'SEG-06',segment_name:'Teadlikud noored',city:'online',loyalty_tier:'silver',main_need:'jätkusuutlikkus ja stiil',preferred_channel:'Instagram',tone_hint:'energiline aga mitte ülemüüdud'}
];

const PROMOTIONS = [
  {promotion_id:'PR-01',promotion_name:'Kevadine garderoob',valid_context:'naiste riided',offer_text:'Uus kevadkollektsioon on e-poes ja poodides',allowed_claims:'uus kollektsioon, ajatud lõiked',do_not_claim:'allahindlust või piiramatut laoseisu',cta:'Vaata kevadkollektsiooni'},
  {promotion_id:'PR-02',promotion_name:'Tööpäeva stiil',valid_context:'meeste riided',offer_text:'Valik mugavaid kontori- ja linnariideid',allowed_claims:'mugavus, lihtne kombineerida',do_not_claim:'ametlik dresscode garantii',cta:'Leia oma argipäeva lemmik'},
  {promotion_id:'PR-03',promotion_name:'Jätkusuutlik valik',valid_context:'aksessuaarid',offer_text:'Eco-certified aksessuaarid teadlikule kliendile',allowed_claims:'eco-certified tooted, praktilisus',do_not_claim:'100% süsinikuneutraalsus',cta:'Tutvu teadliku valikuga'},
  {promotion_id:'PR-04',promotion_name:'Uue poe tervitus',valid_context:'Narva',offer_text:'Narva poe avamise tutvustuskampaania',allowed_claims:'uus pood, kohalik valik',do_not_claim:'täpseid avamisaegu',cta:'Külasta UrbanStyle Narva poodi'},
  {promotion_id:'PR-05',promotion_name:'E-poe nädal',valid_context:'online',offer_text:'E-poes esile tõstetud hooajatooted',allowed_claims:'mugav ostmine, kiire valik',do_not_claim:'tasuta tarne',cta:'Vaata e-poe valikut'},
  {promotion_id:'PR-06',promotion_name:'Capsule wardrobe',valid_context:'naiste riided',offer_text:'Baasesemed, mida saab kombineerida mitmel viisil',allowed_claims:'ajatus, kombineeritavus',do_not_claim:'üks ese sobib kõigile',cta:'Ehita oma capsule wardrobe'}
];

const INVENTORY = [
  {product_id:'US-P-101',online_stock:42,inventory_note:'sobib kampaaniasse'},
  {product_id:'US-P-102',online_stock:12,inventory_note:'kasuta ettevaatlikult, madalam laoseis'},
  {product_id:'US-P-103',online_stock:80,inventory_note:'sobib suurema nähtavusega kampaaniasse'},
  {product_id:'US-P-201',online_stock:30,inventory_note:'sobib kampaaniasse'},
  {product_id:'US-P-202',online_stock:9,inventory_note:'ära luba laialdast saadavust'},
  {product_id:'US-P-203',online_stock:36,inventory_note:'sobib kampaaniasse'},
  {product_id:'US-P-301',online_stock:120,inventory_note:'sobib kampaaniasse'},
  {product_id:'US-P-302',online_stock:26,inventory_note:'sobib piiratud fookusega kampaaniasse'},
  {product_id:'US-P-303',online_stock:18,inventory_note:'kasuta ettevaatlikult'},
  {product_id:'US-P-401',online_stock:21,inventory_note:'sobib väiksema kampaaniaga'},
  {product_id:'US-P-402',online_stock:33,inventory_note:'sobib kampaaniasse'},
  {product_id:'US-P-403',online_stock:65,inventory_note:'sobib kampaaniasse'}
];

function normalize(s){return String(s||'').toLowerCase();}
function matches(text, needle){return normalize(text).includes(normalize(needle));}

// 1. Sihtrühm
let segment = SEGMENTS.find(s => matches(input.segment_hint, s.segment_id) || matches(input.segment_hint, s.segment_name));
if(!segment) segment = SEGMENTS[0];

// 2. Tooted (kuni 3)
let selectedProducts = [];
if(input.product_hint){
  const direct = PRODUCTS.find(p => matches(input.product_hint, p.product_id) || matches(input.product_hint, p.product_name));
  if(direct) selectedProducts.push(direct);
}
if(selectedProducts.length === 0 && input.category){
  selectedProducts = PRODUCTS.filter(p => normalize(p.category) === normalize(input.category)).slice(0, 3);
}
if(selectedProducts.length === 0){
  selectedProducts = PRODUCTS.slice(0, 3);
}

// 3. Kampaania
let promotion = PROMOTIONS.find(p => matches(input.brief, p.promotion_name) || matches(input.brief, p.promotion_id));
if(!promotion){
  const cat = selectedProducts[0]?.category || input.category;
  promotion = PROMOTIONS.find(p => p.valid_context === cat) || PROMOTIONS[0];
}

// 4. Laoseis hoiatus
const inventoryWarnings = selectedProducts.map(p => {
  const inv = INVENTORY.find(i => i.product_id === p.product_id);
  return inv ? `${p.product_name}: ${inv.inventory_note} (online: ${inv.online_stock} tk)` : '';
}).filter(Boolean).join('; ');

// 5. Andmekontekst AI'le
const dataContext = [
  `SIHTRÜHM: ${segment.segment_name} (${segment.city}, ${segment.loyalty_tier})`,
  `Sihtrühma vajadus: ${segment.main_need}`,
  `Eelistatud kanal: ${segment.preferred_channel}, toon: ${segment.tone_hint}`,
  ``,
  `KAMPAANIA: ${promotion.promotion_name} (${promotion.promotion_id})`,
  `Pakkumine: ${promotion.offer_text}`,
  `Lubatud väited: ${promotion.allowed_claims}`,
  `EI TOHI väita: ${promotion.do_not_claim}`,
  `Soovitatud CTA: ${promotion.cta}`,
  ``,
  `TOOTED:`,
  selectedProducts.map(p => `- ${p.product_id} ${p.product_name} (${p.price_eur} EUR, ${p.eco_certified?'eco':'standard'}): ${p.key_message} | ${p.content_angle}`).join('\n'),
  ``,
  `LAOSEISU HOIATUSED: ${inventoryWarnings}`
].join('\n');

return [{
  json: {
    ...input,
    segment_id: segment.segment_id,
    segment_name: segment.segment_name,
    segment_city: segment.city,
    promotion_id: promotion.promotion_id,
    promotion_name: promotion.promotion_name,
    promotion_cta: promotion.cta,
    promotion_do_not_claim: promotion.do_not_claim,
    product_ids: selectedProducts.map(p=>p.product_id).join(', '),
    product_names: selectedProducts.map(p=>p.product_name).join(', '),
    data_context: dataContext,
    is_revision: !!input.feedback
  }
}];

