// =========================================================
// PARSE AI JSON + valmista Telegram sõnumid
// =========================================================
const aiOut = $input.first().json.output || $input.first().json.text || '';
const meta = $('Andmete lookup (N4 andmepakk)').first().json;

let parsed;
try {
  const cleaned = String(aiOut).replace(/```json/gi,'').replace(/```/g,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    telegram: {text: '⚠️ Viga AI väljundis. Vaata workflow execution logi. Algne väljund: ' + String(aiOut).slice(0,200)},
    instagram: {caption: '', hashtags: ''},
    facebook: {text: '', cta: ''},
    email: {subject: '', body: ''},
    tootekirjeldus: {text: ''},
    meta: {quality_ok: false, human_check: ['Kontrolli AI väljundit']}
  };
}

// Salvesta drafti staticData'sse, et PARANDA: saaks selle leida
const staticData = $getWorkflowStaticData('global');
staticData.lastDraftByChat = staticData.lastDraftByChat || {};
staticData.lastDraftByChat[String(meta.chat_id)] = {
  draft_id: meta.draft_id,
  draft_text: parsed.telegram?.text || '',
  product_hint: meta.product_ids,
  segment_hint: meta.segment_id,
  category: meta.category,
  created_at: meta.created_at
};

// Telegram välja vormistamine — vali kanal Form'ist
const channel = (meta.channel || 'Kõik kanalid').toLowerCase();
const showAll = channel.includes('kõik');

const sections = [];
sections.push(`📋 *UrbanStyle N4 sisudraft*`);
sections.push(`Draft ID: \`${meta.draft_id}\` • Allikas: ${meta.source}`);
sections.push(`Sihtrühm: ${meta.segment_name} • Kampaania: ${meta.promotion_name}`);
sections.push(`Tooted: ${meta.product_names}`);
sections.push('');

if(meta.is_revision){
  sections.push(`✏️ *PARANDATUD VERSIOON*`);
  sections.push(`Tagasiside: ${meta.feedback}`);
  sections.push('');
}

if(showAll || channel.includes('telegram')){
  sections.push(`*📱 Telegram:*`);
  sections.push(parsed.telegram?.text || '-');
  sections.push('');
}
if(showAll || channel.includes('instagram')){
  sections.push(`*📸 Instagram:*`);
  sections.push(parsed.instagram?.caption || '-');
  sections.push(parsed.instagram?.hashtags || '');
  sections.push('');
}
if(showAll || channel.includes('facebook')){
  sections.push(`*📘 Facebook:*`);
  sections.push(parsed.facebook?.text || '-');
  sections.push(`CTA: ${parsed.facebook?.cta || meta.promotion_cta}`);
  sections.push('');
}
if(showAll || channel.includes('email')){
  sections.push(`*✉️ Email:*`);
  sections.push(`Subject: ${parsed.email?.subject || '-'}`);
  sections.push(parsed.email?.body || '-');
  sections.push('');
}
if(showAll || channel.includes('tootekirjeldus')){
  sections.push(`*🛍 Tootekirjeldus (e-pood):*`);
  sections.push(parsed.tootekirjeldus?.text || '-');
  sections.push('');
}

sections.push('━━━━━━━━━━━━━━━');
sections.push(`✅ *Inimese kontroll enne avaldamist:*`);
(parsed.meta?.human_check || ['Kontrolli kampaania reegleid','Kontrolli laoseisu','Kontrolli CTA-d']).forEach(c => sections.push(`• ${c}`));
sections.push('');
sections.push(`💬 Tagasiside: kirjuta botile \`PARANDA: <sinu juhis>\``);

const telegramText = sections.join('\n');

return [{
  json: {
    chat_id: meta.chat_id,
    telegram_text: telegramText,
    draft_id: meta.draft_id,
    parsed,
    meta
  }
}];
